import bisect
class MKAverage:
    def __init__(self, m: int, k: int):
        self.m = m
        self.k = k
        self.q = []
        self.sorted = []
    def addElement(self, num: int) -> None:
        self.q.append(num)
        bisect.insort(self.sorted, num)
        if len(self.q) > self.m:
            old = self.q.pop(0)
            idx = bisect.bisect_left(self.sorted, old)
            self.sorted.pop(idx)
    def calculateMKAverage(self) -> int:
        if len(self.q) < self.m:
            return -1
        mid = self.sorted[self.k:self.m - self.k]
        return sum(mid) // len(mid)

