function lowerBound(arr, x) {
    let lo = 0, hi = arr.length;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (arr[mid] < x) lo = mid + 1; else hi = mid;
    }
    return lo;
}
var MKAverage = function(m, k) {
    this.m = m;
    this.k = k;
    this.q = [];
    this.sorted = [];
};
MKAverage.prototype.addElement = function(num) {
    this.q.push(num);
    const pos = lowerBound(this.sorted, num);
    this.sorted.splice(pos, 0, num);
    if (this.q.length > this.m) {
        const old = this.q.shift();
        const idx = lowerBound(this.sorted, old);
        this.sorted.splice(idx, 1);
    }
};
MKAverage.prototype.calculateMKAverage = function() {
    if (this.q.length < this.m) return -1;
    let sum = 0;
    for (let i = this.k; i < this.m - this.k; i++) sum += this.sorted[i];
    const cnt = this.m - 2 * this.k;
    return Math.floor(sum / cnt);
};
